const now = new Date();
const year = now.getUTCFullYear();
const week = Math.ceil((((now - new Date(Date.UTC(year,0,1))) / 86400000) + new Date(Date.UTC(year,0,1)).getUTCDay() + 1) / 7);
return [{ json: {
  week_key: year + '-W' + String(week).padStart(2, '0'),
  target_count: 7,
  language: 'ar',
  platform_primary: 'YOUTUBE_SHORTS',
  format: '9:16',
  duration_target_sec: 45,
  default_template_id: 'new_era_dark_editorial',
  default_render_environment: 'LOCAL',
  categories: ['New Era Emotions','Modern Human Condition','AI & Creativity','Creative Thinking','Productivity','Philosophy'],
  series: ['New Era Emotions Lexicon','Modern Human Questions','RAIZ Creative Signals']
}}];

const ai = $input.first().json;
const brief = $('Build Autopilot Brief').first().json;
function scan(v) {
  if (typeof v === 'string') return v;
  if (Array.isArray(v)) { for (const x of v) { const r = scan(x); if (r) return r; } }
  if (v && typeof v === 'object') {
    for (const key of ['output','output_text','text','content','message','response','mergedResponse','data']) {
      if (v[key]) { const r = scan(v[key]); if (r) return r; }
    }
    for (const x of Object.values(v)) { const r = scan(x); if (r) return r; }
  }
  return '';
}
let raw = scan(ai) || JSON.stringify(ai);
const tick = String.fromCharCode(96); raw = raw.split(tick + tick + tick + 'json').join('').split(tick + tick + tick).join('').trim();
let parsed;
try { parsed = JSON.parse(raw); } catch (e) { parsed = { ideas: [] }; }
const fallback = [{
  category:'New Era Emotions',
  series_name:'New Era Emotions Lexicon',
  title_working:'الهوية المعلقة',
  idea_text:'شخص يعرف نفسه داخليًا لكنه لا يعرف كيف يعيش هذه الهوية وسط توقعات الناس.',
  hook_angle:'إنت عارف نفسك… بس مش عارف تعيشها.',
  audience:'المبدع / الموظف / الإنسان الحديث',
  creative_direction:'أسود وأبيض، ورقة بيضاء، علامة حمراء واحدة، إحساس وثيقة نفسية',
  priority:1,
  source_type:'AUTOPILOT_FALLBACK',
  trend_signal:'identity fatigue',
  search_basis:'fallback'
}];
const ideas = Array.isArray(parsed.ideas) && parsed.ideas.length ? parsed.ideas : fallback;
const now = new Date().toISOString();
const stamp = Date.now();
return ideas.slice(0, Number(brief.target_count || 7)).map((idea, index) => {
  const seq = String(index + 1).padStart(3, '0');
  const videoId = 'RVF-' + brief.week_key + '-' + seq + '-' + stamp;
  return { json: {
    video_id: videoId,
    idea_id: 'IDEA-' + brief.week_key + '-' + seq + '-' + stamp,
    trend_id: '',
    source_type: idea.source_type || 'AUTOPILOT_RESEARCH',
    language: 'ar',
    platform_primary: 'YOUTUBE_SHORTS',
    format: '9:16',
    duration_target_sec: 45,
    category: idea.category || 'New Era Emotions',
    series_name: idea.series_name || 'RAIZ Creative Signals',
    title_working: idea.title_working || 'RAIZ Idea ' + seq,
    idea_text: idea.idea_text || '',
    hook_angle: idea.hook_angle || '',
    audience: idea.audience || 'الإنسان الحديث / المبدع العربي',
    creative_direction: idea.creative_direction || 'أسود وأبيض، دفء إنساني، نص عربي واضح، إيقاع هادئ',
    priority: Number(idea.priority || index + 1),
    approval_status: 'APPROVED',
    main_status: 'APPROVED',
    current_stage: 'SCRIPT',
    assigned_workflow: 'daily_short_factory_v1',
    n8n_lock: false,
    retry_count: 0,
    max_retries: 3,
    quality_status: 'PENDING',
    human_review_required: false,
    publish_status: 'NOT_READY',
    created_at: now,
    updated_at: now,
    notes: 'Autogenerated by RAIZ Weekly Idea Autopilot. trend_signal=' + (idea.trend_signal || '') + '; search_basis=' + (idea.search_basis || ''),
    template_id: 'new_era_dark_editorial',
    template_version: 'v1.0',
    render_environment: 'LOCAL',
    render_worker_id: 'local_docker',
    render_mode: 'local_only',
    template_release_id: 'REL-2026-001',
    local_render_status: 'PENDING',
    docker_test_status: 'PENDING',
    doc_source_of_truth: 'DOCS_FOR_LONG_TEXT__SHEETS_FOR_STATUS'
  }};
});
